(window.webpackJsonp=window.webpackJsonp||[]).push([[834],{794:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[]}</span> <span class=\\"hljs-variable\\">arr</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number}</span> <span class=\\"hljs-variable\\">k</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{boolean}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> canArrange = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">arr, k</span>) </span>{\\n    <span class=\\"hljs-keyword\\">let</span> modArr=[]\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> n <span class=\\"hljs-keyword\\">of</span> arr){\\n        modArr.push((n+k*<span class=\\"hljs-number\\">10000000</span>) % k)\\n    }\\n    <span class=\\"hljs-keyword\\">let</span> count={}\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> n <span class=\\"hljs-keyword\\">of</span> modArr){\\n        <span class=\\"hljs-keyword\\">if</span>(count[n]==<span class=\\"hljs-literal\\">null</span>)count[n]=<span class=\\"hljs-number\\">1</span>\\n        <span class=\\"hljs-keyword\\">else</span> count[n]++\\n    }\\n    <span class=\\"hljs-comment\\">// console.log(count,k)</span>\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> key <span class=\\"hljs-keyword\\">in</span> count){\\n        <span class=\\"hljs-keyword\\">let</span> nxt=(k - (+key)) % k\\n        <span class=\\"hljs-keyword\\">while</span>(count[key]&gt;<span class=\\"hljs-number\\">0</span>){\\n            <span class=\\"hljs-keyword\\">if</span>(!count[nxt])<span class=\\"hljs-keyword\\">return</span> <span class=\\"hljs-literal\\">false</span>\\n            count[key]--\\n            <span class=\\"hljs-keyword\\">if</span>(!count[nxt])<span class=\\"hljs-keyword\\">return</span> <span class=\\"hljs-literal\\">false</span>\\n            count[nxt]--\\n        }\\n    }\\n    <span class=\\"hljs-keyword\\">return</span> <span class=\\"hljs-literal\\">true</span>\\n};\\n</code></pre>\\n"],"titleSlug":"check-if-array-pairs-are-divisible-by-k","hasThinking":false,"content":"<p>\u7ed9\u4f60\u4e00\u4e2a\u6574\u6570\u6570\u7ec4 <code>arr</code> \u548c\u4e00\u4e2a\u6574\u6570 <code>k</code> \uff0c\u5176\u4e2d\u6570\u7ec4\u957f\u5ea6\u662f\u5076\u6570\uff0c\u503c\u4e3a <code>n</code> \u3002</p>\\n\\n<p>\u73b0\u5728\u9700\u8981\u628a\u6570\u7ec4\u6070\u597d\u5206\u6210 <code>n /&nbsp;2</code> \u5bf9\uff0c\u4ee5\u4f7f\u6bcf\u5bf9\u6570\u5b57\u7684\u548c\u90fd\u80fd\u591f\u88ab <code>k</code> \u6574\u9664\u3002</p>\\n\\n<p>\u5982\u679c\u5b58\u5728\u8fd9\u6837\u7684\u5206\u6cd5\uff0c\u8bf7\u8fd4\u56de <em>True</em> \uff1b\u5426\u5219\uff0c\u8fd4\u56de <em>False</em> \u3002</p>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>arr = [1,2,3,4,5,10,6,7,8,9], k = 5\\n<strong>\u8f93\u51fa\uff1a</strong>true\\n<strong>\u89e3\u91ca\uff1a</strong>\u5212\u5206\u540e\u7684\u6570\u5b57\u5bf9\u4e3a (1,9),(2,8),(3,7),(4,6) \u4ee5\u53ca (5,10) \u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>arr = [1,2,3,4,5,6], k = 7\\n<strong>\u8f93\u51fa\uff1a</strong>true\\n<strong>\u89e3\u91ca\uff1a</strong>\u5212\u5206\u540e\u7684\u6570\u5b57\u5bf9\u4e3a (1,6),(2,5) \u4ee5\u53ca (3,4) \u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 3\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>arr = [1,2,3,4,5,6], k = 10\\n<strong>\u8f93\u51fa\uff1a</strong>false\\n<strong>\u89e3\u91ca\uff1a</strong>\u65e0\u6cd5\u5728\u5c06\u6570\u7ec4\u4e2d\u7684\u6570\u5b57\u5206\u4e3a\u4e09\u5bf9\u7684\u540c\u65f6\u6ee1\u8db3\u6bcf\u5bf9\u6570\u5b57\u548c\u80fd\u591f\u88ab 10 \u6574\u9664\u7684\u6761\u4ef6\u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 4\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>arr = [-10,10], k = 2\\n<strong>\u8f93\u51fa\uff1a</strong>true\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 5\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>arr = [-1,1,-2,2,-3,3,-4,4], k = 3\\n<strong>\u8f93\u51fa\uff1a</strong>true\\n</pre>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>arr.length == n</code></li>\\n\\t<li><code>1 &lt;= n &lt;= 10^5</code></li>\\n\\t<li><code>n</code> \u4e3a\u5076\u6570</li>\\n\\t<li><code>-10^9 &lt;= arr[i] &lt;= 10^9</code></li>\\n\\t<li><code>1 &lt;= k &lt;= 10^5</code></li>\\n</ul>\\n","title":"1497. \u68c0\u67e5\u6570\u7ec4\u5bf9\u662f\u5426\u53ef\u4ee5\u88ab k \u6574\u9664","relatedTags":["\u8d2a\u5fc3\u7b97\u6cd5","\u6570\u7ec4","\u6570\u5b66"],"difficult":"Middle","lang":["javascript"],"uniqueID":"1497"}')}}]);